effect.shader:
void main() {
    vec2 UV = acScreenNorm;
    vec2 center = acLayerCenterNorm-(centerPoint/1000. * vec2(-1.,1.));

    UV -= center;
    UV.x *= acScreenSize.x / acScreenSize.y;
    float dist = length(UV);
    if ( dist < radius ) {
        float p = dist / radius;
        if(strength > 0.) {
            UV *= mix(1.0, smoothstep(0.0, radius / dist, p), strength * 0.75);
        } else {
            UV *= mix(1.0, pow(p, 1.0 + strength * 0.75) * radius / dist, 1.0 - p);
        }
    }
    UV.x /= acScreenSize.x / acScreenSize.y;
    UV += center;

    gl_FragColor = texture2DCv(inputImg.texture,UV);

}
